def solve(panel_configurations):
    if not panel_configurations:
        return []

    results = []
    for config in panel_configurations:
        # Assuming each config is a dictionary with 'breakers' key
        if 'breakers' in config:
            results.append(config['breakers'])
        else:
            results.append([])  # Default to empty if no breakers found

    return results
